const authHeader = $input.item.json.headers?.authorization || '';
const token = authHeader.replace('Bearer ', '');

if (token === 'mock-jwt-token-123') {
  return [{ json: { valid: true, user: { id: 1, role: 'Employee', email: 'employee@autohr.com' } } }];
} else if (token === 'mock-hr-token') {
  return [{ json: { valid: true, user: { id: 2, role: 'HR', email: 'hr@autohr.com' } } }];
} else if (token === 'mock-admin-token') {
  return [{ json: { valid: true, user: { id: 3, role: 'Admin', email: 'admin@autohr.com' } } }];
}

return [{ json: { valid: false } }];

const role = $node["Verify Token"].json["user"]["role"];

if (role === 'Employee') {
  return [{ json: { success: true, stats: { available: 12, used: 6, pending: 1, approved: 5 } } }];
} else if (role === 'HR') {
  return [{ json: { success: true, stats: { employees: 85, pendingApp: 14, leavesThisMonth: 32 } } }];
} else {
  return [{ json: { success: true, stats: { teamMembers: 12, pendingApp: 4, approved: 9 } } }];
}
